mapper.update:
UPDATE game_records
SET nav_path = #{navPath}, last_article = #{lastArticle}
WHERE record_id = #{recordId}
  AND account_id = #{accountId}
  AND status = 'in_progress'

UPDATE game_records
SET status = 'cleared', nav_path = #{navPath}, elapsed_ms = #{elapsedMs}, last_article = NULL
WHERE record_id = #{recordId}
  AND account_id = #{accountId}
  AND status = 'in_progress'

UPDATE game_records
SET status = 'abandoned', last_article = NULL
WHERE record_id = #{recordId}
  AND account_id = #{accountId}
  AND status = 'in_progress'

mapper.delete:
DELETE FROM game_records
WHERE record_id IN (
    SELECT record_id FROM game_records
    WHERE account_id = #{accountId}
      AND status IN ('cleared', 'abandoned')
    ORDER BY played_at DESC
    OFFSET #{keepCount}
)
